VALUES
  ('diplomatic-20fe77d5-moex-00694', 'diplomatic-20fe77d5', 'diplomatic-20fe77d5-moex-110-c655adf3', 'sub-diplomatic-20fe77d5-04', NULL, 'single_choice', '下列何者非屬各國辦理公民投票的考量範圍？', '["公投結果是否能超過半數門檻", "對政黨制度的干預或影響", "尋求直接民意與間接民意之合致", "國會的支持與反對意見"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:37+00:00", "source_pdf_sha1": "4869a4c6fee1", "answer_pdf_sha1": "9956c1dccdce", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "101", "s": "0604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "綜合法政知識(包括中華民國憲法、兩岸關係、比較政府與政治)", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-韓文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00001', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '下列情境語句，何者用法最為恰當？', '["新居落成：「屋上建瓴，恭喜新居落成。」", "活動開幕：「感謝各位的蒞臨，讓這次的展覽可以厚往薄來。」", "榮退餐會：「恭喜您可以自在逍遙，從今以後可以快意恩仇了。」", "婚禮祝賀：「在這兩家合婚的大好日子，要祝福新人喜結良緣、花好月圓。」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00002', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「不要忘記生命才是創作中最重要的一環。在我們對戲劇理論抱持激情的時候，記 得要先對生命抱持激情。對生命敏感，對人好奇，對現行的世界保有批判的態度， 同時擁有廣納包容的胸襟。」 下列敘述，何者最貼近本文意旨？', '["人要正向思考，不能輕言放棄生命", "好的編劇不僅熟知理論，也對生活周遭充滿關注與熱情", "為人當有雅量，不該對別人好奇，凡事包容體諒即是尊重", "教師教導戲劇理論時不能僅照本宣科，也應教學生認真生活"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00003', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「歷史從來都有些勢利眼。歷史的一切總要透過『層積堆疊』，經過『集體記憶』的 萃取純化，方才得以逐漸定型。然而，在此『歷史造山運動』過程之中，歷史的光 圈很容易只集中在『歷史時刻』，相對地，『時刻之前』的脈絡面貌，卻常常會被有 意無意地遺忘或改變了。」 最適合用來說明上文的是：', '["人類歷史經過漫長時間累積，是給後世的智慧結晶", "過往的歷史充滿許多偏見，編修史書尤須格外謹慎", "閱讀歷史如果僅集中特定時刻，容易忽略前後脈絡", "歷史是屬於不同族群的集體記憶，應注意地方差異"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00004', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「別忘了這是個國際化的時代。到哪裡都看得到同樣的連鎖速食店、同樣的二十四 小時便利商店、同樣的好萊塢電影海報。完全陌生的角落正逐漸從這個世界上消失。 在這樣的時代我們怎麼可能還有完全的流浪？像馬可波羅、哥倫布那樣，踏上一塊 完全沒有線索可循的土地，連送信回家的信差都沒有，在我們這個時代已經越來越 像則神話。在這個所有角落越來越像的世界裡，怎麼可能還有完全的流浪？」 下列說明，最切近上文主旨的是：', '["人們渴望流浪的感覺", "最好的旅行是如同探險家一般地發現新世界", "世界趨向高度同質化，因此人們認識在地就等於認識了全世界", "全球化之下，各地過多的文化複製空間所帶來的熟悉感，將影響人們的旅行經驗"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00005', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「攝影者開始發現自然界的詩意後便停不下來，畢竟捕捉動物一瞬間運動狀態的不 只是機械，還是心靈。美的喚醒如此獨特，以至於同樣一台機械交給不同的人將獲 致不同的結果，而同樣一張照片帶給觀看者的情緒震動，也絕對不是那些一開始希 望相機為科學理性服務的人所能理解的。」 下列選項，何者最不符合上文旨意？', '["相機產生有意義的畫面，是因攝影者使用的機械不同", "照片凝止自然界的運動，使觀看者更能體會自然之美", "照片讓觀看者情緒震動，因相機能捕捉動物瞬間樣態", "影像在藝術與科學間飛翔，透過心靈喚醒自然界之美"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00006', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「後來我聽說，拉小提琴和中提琴的樂手，也會得同樣的毛病。他們的手因為長時 間在把絃上緊壓琴弦，都會長出厚繭來，但究竟比不上大提琴，因為大提琴的把位 較寬而琴弦較粗的緣故。另外低音提琴的把位更長、琴弦更粗，但一是低音提琴演 奏的機會不多，一是低音提琴很多時候是撥弦用來作打拍子的樂器，所以低音大提 琴手得這個毛病可能不太嚴重。不過據音樂界的朋友說，手指上長厚皮，在弦樂演 奏家身上來講，是再正常不過的事了。還有一種『形象』極為優美的樂器——豎琴， 是一種純粹撥弦的樂器，演奏豎琴，須用十指撥弦，因此豎琴演奏家勢必十指都會 長出繭來，比起大提琴家，他們付的代價可能更大呢。」 下列選項，最符合上文敘述的是：', '["演奏琴弦最粗的低音提琴，手指長的繭也最厚", "演奏把位越窄的弦樂器，手指就越容易長出厚繭", "豎琴家往往十指長繭，主要是因為豎琴的琴弦最多", "低音大提琴的演奏特點，可能會減輕手指長繭的程度"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00007', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「回到屋裡，我輕腳輕手，一溜煙跑到樓上躲進自己房中去了。我不敢張聲，生怕 他們曉得我挨老師留堂。哪曉得才過一下子，胖子大娘就扯起喉嚨上樓來找我了， 胖子大娘說是矮子舅媽帶了一個叫玉卿嫂的女人來帶我，在下面等著呢。矮子舅媽 能帶什麼好人來？我頂討厭她。我下樓到客廳裡時，一看見站在矮子舅媽旁邊的玉 卿嫂卻不由得倒抽了一口氣，好爽淨，一身月白色的短衣長褲，腳底一雙帶絆的黑 布鞋，一頭烏油油的頭髮學那廣東婆媽鬆鬆的挽了一個髻兒，一雙杏仁大的白耳墜 子卻剛剛露在髮腳子外面，淨扮的鴨蛋臉，水秀的眼睛……」 根據上文，「我」的情感轉折為：', '["由膽怯而厭惡，轉而驚訝", "由焦慮而憤怒，轉而雀躍", "由拘謹而抗拒，轉而驚嚇", "由緊張而期待，轉而歡喜"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00008', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「大部分人的語言能力主要由左半腦負責。語言產生和布氏區（Broca’sarea）有關， 語言理解和威氏區（Wernicke’s area）有關，這兩個區域之間藉由弓形束（arcuate fasciculus）獲得聯繫。語言學習具有關鍵期，但學習第二語言並非越早越好！語言 學習占用大腦資源和時間，除非在兩種語言都有豐富學習機會的雙語環境下，否則 應該到認知功能與大腦發展差不多後，懂得運用學習的策略和技巧，再來學第二語 言會更恰當！」 根據上文，下列選項何者最符合文意？', '["人類的語言功能完全由左半腦中的布氏區、威氏區負責", "布氏區處理語言理解，威氏區與語言產生有關，弓形束聯繫兩者", "學習者如無雙語環境，最好等大腦認知功能較成熟後，再學習第二語言", "語言學習具有關鍵期，三歲之後發音方法固定，因此學習第二語言越早越好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL),
  ('diplomatic-36ccc47a-moex-00009', 'diplomatic-36ccc47a', 'diplomatic-36ccc47a-moex-114-13504c0c', 'sub-diplomatic-36ccc47a-01', NULL, 'single_choice', '「法語的松鼠毛（Vair）音同於玻璃（Verre）。在十七世紀，蘇格蘭、愛爾蘭、加泰 隆尼亞（在今西班牙）一帶，玻璃是罕見且珍貴的，於是，一六九七年法國作家夏 爾．佩羅（CharlesPerrault）在記述灰姑娘故事時便訛誤（或改編？）為玻璃鞋了。 人們都愛童話故事，因為真正的生活總是那樣的蒼白與無奈，在故事中尋找一個浪 漫美好的夢，即使明知是虛假的，我們都享受那樣被矇迷的片刻啊！」 根據上文，下列選項最符合文意的是：', '["日常生活中，我們常常運用音同，而創造出許多新鮮的詞彙", "許多習以為常的事物，若從語源上追溯可以發覺不同的面貌", "大部分的人都喜歡童話故事，因可以陶醉在浪漫愛情的時光", "灰姑娘的童話故事，玻璃鞋的使用有誤，造成內容蒼白無奈"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:25:24+00:00", "source_pdf_sha1": "3403830e86e7", "answer_pdf_sha1": "dbb86ff29ebd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0101", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-越南文組"}'::jsonb, NULL)
